//-------------------------------------------------------------------------
// 조회 : 데이터를 조회한다.
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  if (!$c.gus.cfValidate($p, [tbl_search])) return;

  // 버전이 001일경우는 장부구분의 (자산비용)을 조회 하도록 코드값을 변경한다.
  if (lc_version.getValue() == "001" || lc_version.getValue() == "000") {
    // 일반일경우
    if (lc_srchBookClsCd.getValue() == "601") {
      dma_search.set("bookClsCd", "621");
      // 요약일경우
    } else if (lc_srchBookClsCd.getValue() == "602") {
      dma_search.set("bookClsCd", "622");
      // 상세일경우
    } else if (lc_srchBookClsCd.getValue() == "603") {
      dma_search.set("bookClsCd", "623");
    }
  }
  gr_master.setNoResultMessageVisible(false);
  ds_master.reform();
  ds_master.removeAll();
  totalRows.setValue("0");
  dma_search.set("acctDeptCd", lc_acctDeptCd.getValue());

  // console.log("=============> scwin.p_acctDeptCd:"+scwin.p_acctDeptCd+", lc_acctDeptCd.getValue():"+lc_acctDeptCd.getValue()+", acctDeptCd:"+dma_search.get("acctDeptCd"));
  dma_search.set("acctDeptCd", lc_acctDeptCd.getValue());
  let e = await $c.sbm.execute($p, sbm_master);
  scwin.sbm_master_submitdone(e);
};

