scwin.f_detail = async function (rowIndex, Colid) {
  // console.log("f_detail - rowIndex : "+rowIndex);	
  // console.log("f_detail - Colid : "+Colid);
  // console.log("slipProcYn:"+ds_master.getCellData(rowIndex, "slipProcYn"));

  if (ds_master.getRowCount() <= 0) {
    $c.win.alert($p, "월별 실적이 존재하지 않습니다.");
    return false;
  }
  var v_cols_mm = "";
  const cols = ["rsltsAmt01", "rsltsAmt02", "rsltsAmt03", "rsltsAmt04", "rsltsAmt05", "rsltsAmt06", "rsltsAmt07", "rsltsAmt08", "rsltsAmt09", "rsltsAmt10", "rsltsAmt11", "rsltsAmt12"];
  const cols_mm = ["01", "02", "03", "04", "05", "06", "07", "08", "09", "10", "11", "12"];
  for (var i = 0; i < cols.length; i++) {
    if (cols[i] == Colid) {
      v_cols_mm = cols_mm[i];
      break;
    }
  }
  if (ds_master.getRowCount() <= 0) {
    $c.win.alert($p, "사업영역별계획대비실적이 존재하지 않습니다.");
    return false;
  }
  if ($c.gus.cfIsNull($p, v_cols_mm)) {
    return;
  } else {
    //console.log("v_cols_mm:"+v_cols_mm);
    //console.log("v_cols_mm:"+ds_master.getCellData(rowIndex, "rsltsAmt"+v_cols_mm));
    if (ds_master.getCellData(rowIndex, "rsltsAmt" + v_cols_mm) == 0 || ds_master.getCellData(rowIndex, "slipProcYn") != 1) {
      return;
    }
  }
  var p_closeYm = ed_srchCloseYm.getValue().substring(0, 4) + v_cols_mm;
  let data = {
    closeYm: p_closeYm,
    acctDeptCd: lc_acctDeptCd.getValue(),
    acctDeptNm: lc_acctDeptCd.getText("true"),
    acctCd: ds_master.getCellData(rowIndex, "mgntAcctCd"),
    mgntAcctNm: ds_master.getCellData(rowIndex, "mgntAcctCdNm"),
    ver: lc_version.getValue(),
    bizDomCd: ed_bizDomCd.getValue(),
    bizDomNm: ed_bizDomNm.getValue(),
    coCd: ed_coCd.getValue(),
    coNm: ed_coNm.getValue()
  };
  scwin.opts = {
    id: "pop4040128p",
    title: "상세내역",
    popupName: "상세내역",
    modal: true,
    center: "yes",
    type: "browserPopup",
    width: "1500px",
    height: "930px",
    scroll: "no",
    resizable: "no",
    status: "yes"
  };
  scwin.url = "/ui/ac/co/rsltsmgnt/rsltsanl/co_404_01_28p.xml";
  let returnValue = await $c.win.openPopup($p, scwin.url, scwin.opts, data);
};

