scwin.f_Excel = async function () {
  if (ds_master.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    return;
  }
  let gridColCount = gr_master.getTotalCol();
  // for(let i = 0; i < gr_master.getTotalCol(); i++){
  //     if(gr_master.getColumnVisible(i)==true){
  //         gridColCount++;
  //     }
  // }

  let str = $c.gus.cfGetFormatStr($p, ed_srchCloseYm.getValue(), "####/##");
  let str1 = $c.gus.cfGetFormatStr($p, ed_srchCloseYm.getValue(), "######");
  let str2 = scwin.p_acctDeptCd;
  let str21 = lc_acctDeptCd.getText(true);
  let startRowIndex = 0;
  let infoArr = [{
    rowIndex: 0,
    colIndex: 0,
    colSpan: gridColCount,
    rowSpan: 1,
    text: str21 + "(" + str1 + ")",
    textAlign: "center",
    // fontWeight : "bold",
    fontSize: 18,
    drawBorder: true,
    color: "black",
    backgroundColor: "white"
  }, {
    rowIndex: 2,
    colIndex: 0,
    colSpan: gridColCount,
    rowSpan: 1,
    text: "단위_" + lc_unit.getText(true),
    textAlign: "right",
    fontSize: 12,
    drawBorder: false,
    color: "black",
    backgroundColor: "#ffffff"
  }];
  const options = {
    fileName: "월별추이실적_" + str21 + "_" + str1 + ".xlsx",
    sheetName: "월별추이실적_" + str21 + "_" + str1,
    startRowIndex: 4,
    startColumnIndex: 0,
    type: 1,
    hiddenVisible: true
  };
  await $c.data.downloadGridViewExcel($p, gr_master, options, infoArr);
};

